
  CREATE TABLE "DIRKSPZM32"."APS_PLAN_STATUS" 
   (	"SID" VARCHAR2(2 CHAR) DEFAULT '01' NOT NULL ENABLE, 
	"FIRMA_NR" NUMBER(2,0) DEFAULT 1 NOT NULL ENABLE, 
	"APS_STATUS" VARCHAR2(3 CHAR), 
	"PLAN_STATUS" VARCHAR2(30 CHAR), 
	"APS_MODE" NUMBER(1,0) DEFAULT 1 NOT NULL ENABLE, 
	"APS_INTERVAL_SEC" NUMBER(5,0) DEFAULT 600 NOT NULL ENABLE, 
	"APS_COMMAND" VARCHAR2(30 CHAR), 
	"PLAN_TS_START" DATE DEFAULT sysdate NOT NULL ENABLE, 
	"PLAN_TS_END" DATE, 
	"INFO_DEBUG" VARCHAR2(4000 CHAR), 
	"MESSAGE_CODE" NUMBER(5,0), 
	"MESSAGE_TEXT" VARCHAR2(255 CHAR), 
	"ERZ_DATUM" DATE DEFAULT sysdate NOT NULL ENABLE, 
	"ERZ_LOGIN_ID" NUMBER(*,0) DEFAULT -1 NOT NULL ENABLE, 
	"AEND_DATUM" DATE, 
	"AEND_LOGIN_ID" NUMBER(*,0)
   ) ;
ALTER TABLE "DIRKSPZM32"."APS_PLAN_STATUS" ADD CONSTRAINT "APS_COMMAND_CHK" CHECK (aps_command in ('StartAuto','StopAuto',	'Run', 
'Abort', 'Reset')) ENABLE;
ALTER TABLE "DIRKSPZM32"."APS_PLAN_STATUS" ADD CONSTRAINT "APS_STATUS_CHK" CHECK (APS_STATUS in ('PS', 'PE', 'PA', 'IMP', 'EXP', 'U', 'UE')) ENABLE;
ALTER TABLE "DIRKSPZM32"."APS_PLAN_STATUS" ADD CONSTRAINT "PK_APS_PLAN_STATUS" PRIMARY KEY ("SID", "FIRMA_NR")
  USING INDEX  ENABLE;
ALTER TABLE "DIRKSPZM32"."APS_PLAN_STATUS" ADD CONSTRAINT "PLAN_STATUS_CHK" CHECK (PLAN_STATUS in ('Canceled', 'Created', 'Faulted', 'RanToCompletion', 'Running', 'WaitingForActivation', 'WaitingForChildrenToComplete', 'WaitingToRun')) ENABLE;


